import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface CareTask {
  task: string;
  date: string;
}

interface PlantData {
  plantName: string;
  nextWatering: string;
  soilMoistureLevel: string;
  careSchedule: CareTask[];
  moistureTrend: number[];
}

export default function Widget() {
  const plantData = response.data as PlantData;
  const { plantName, nextWatering, soilMoistureLevel, careSchedule, moistureTrend } = plantData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              {plantName}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Next Watering: {nextWatering}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Soil Moisture: {soilMoistureLevel}
            </Typography>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: moistureTrend,
                color: '#4CAF50',
                curve: 'linear',
                showMark: false,
              },
            ]}
            xAxis={[{ data: moistureTrend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {careSchedule.slice(0, 3).map((task, index) => (
              <Chip key={index} label={`${task.task} on ${task.date}`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
